class Cache:
    def __init__(self) -> None:
        self._rows: dict[str, Row] = {}

    def lookup(self, key: str) -> Row | None:
        return self._rows.get(key)

def _parse_response(self, response: httpx.Response) -> dict[str, object] | None:
    try:
        payload = response.json()
    except ValueError as exc:
        self._audit.record_quarantine("vendor_json", str(exc))
        return None
    if not isinstance(payload, dict):
        self._audit.record_quarantine("vendor_json_type", type(payload).__name__)
        return None
    return payload

