EVENT_KINDS = {"started", "completed", "failed"}

def decode_event(row: AuditRow) -> Event:
    if row.kind not in EVENT_KINDS:
        raise ValueError(f"invalid audit event kind: {row.kind!r}")
    return Event(kind=row.kind, run_id=row.run_id)

def _collect_rows(self, plugin: TransformPlugin, row: Row) -> list[Row]:
    plugin_result = plugin.transform(row)
    return list(getattr(plugin_result, "rows", []))

